const n=document.getElementById("nav-hamburger"),t=document.getElementById("nav-mobile");n.addEventListener("click",()=>{const e=t.classList.toggle("open");n.setAttribute("aria-expanded",String(e)),t.setAttribute("aria-hidden",String(!e)),document.body.style.overflow=e?"hidden":""});t.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{t.classList.remove("open"),n.setAttribute("aria-expanded","false"),t.setAttribute("aria-hidden","true"),document.body.style.overflow=""})});
